<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***SimpleDatabaseChecker*Basicdatabasestructureanddatavalidation*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';classSimpleDatabaseChecker{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Basicdatabasecheck*/publicfunctioncheckDatabase(){$results=[];/Checkconnection$results['connection']=$this->checkConnection();/Checktables$results['tables']=$this->checkTables();/Checkdatacounts$results['data_counts']=$this->checkDataCounts();/Checkbasicdataintegrity$results['data_integrity']=$this->checkDataIntegrity();return$results;}/***Checkdatabaseconnection*/privatefunctioncheckConnection(){try{$version=$this->pdo->query("SELECTVERSION()asversion")->fetch();return['status'=>'connected','version'=>$version['version'],'database'=>DB_NAME];}catch(Exception$e){return['status'=>'error','error'=>$e->getMessage()];}}/***Checkbasictablestructure*/privatefunctioncheckTables(){$tables=[];/Gettablelist$stmt=$this->pdo->query("SHOWTABLES");while($row=$stmt->fetch(PDO::FETCH_NUM)){$tableName=$row[0];/Getbasictableinfo$stmt2=$this->pdo->query("SELECTCOUNT(*)ascountFROM`".$tableName."`");$count=$stmt2->fetch()['count'];$tables[$tableName]=['row_count'=>(int)$count,'status'=>'exists'];}return$tables;}/***Checkdatacounts*/privatefunctioncheckDataCounts(){$counts=[];/Coretables$tables_to_check=['personil','unsur','bagian','jabatan','pangkat','master_jenis_pegawai'];forforeach($tables_to_checkas$table){try{$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROM`".$table."`");$counts[$table]=(int)$stmt->fetch()['count'];}catch(Exception$e){$counts[$table]='error:'.$e->getMessage();}}return$counts;}/***Checkbasicdataintegrity*/privatefunctioncheckDataIntegrity(){$issues=[];try{/Checkpersonilwithinvalidreferences$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilpWHEREp.is_deleted=0AND((p.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=p.id_unsur))OR(p.id_bagian>0ANDNOTEXISTS(SELECT1FROMbagianbWHEREb.id=p.id_bagian))OR(p.id_jabatan>0ANDNOTEXISTS(SELECT1FROMjabatanjWHEREj.id=p.id_jabatan)))");$invalid_refs=$stmt->fetch()['count'];if($invalid_refs>0){$issues[]="Found{$invalid_refs}personilwithinvalidreferences";}/CheckduplicateNRP$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROM(SELECTnrp,COUNT(*)ascntFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''GROUPBYnrpHAVINGcnt>1)duplicates");$duplicate_nrp=$stmt->fetch()['count'];if($duplicate_nrp>0){$issues[]="Found{$duplicate_nrp}duplicateNRPvalues";}/Checkbagianwithinvalidunsur$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMbagianbWHEREb.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=b.id_unsur)");$invalid_bagian=$stmt->fetch()['count'];if($invalid_bagian>0){$issues[]="Found{$invalid_bagian}bagianwithinvalidunsurreference";}/Checkjabatanwithinvalidunsur$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMjabatanjWHEREj.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=j.id_unsur)");$invalid_jabatan=$stmt->fetch()['count'];if($invalid_jabatan>0){$issues[]="Found{$invalid_jabatan}jabatanwithinvalidunsurreference";}}catch(Exception$e){$issues[]="Errorcheckingdataintegrity:".$e->getMessage();}return['issues'=>$issues,'status'=>empty($issues)?'ok':'has_issues'];}}/Runcheckifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$checker=newSimpleDatabaseChecker();$result=$checker->checkDatabase();echojson_encode(['success'=>true,'data'=>$result,'timestamp'=>date('c')]);}catch(Exception$e){echojson_encode(['success'=>false,'message'=>$e->getMessage(),'timestamp'=>date('c')]);}}?>
